function e(){document.querySelectorAll(`.ct-form-input input`).forEach(e=>{let t=e.closest(`.ct-form-input`);e.value&&t.classList.add(`has-content`),e.addEventListener(`focus`,()=>{t.classList.add(`has-content`)}),e.addEventListener(`blur`,()=>{e.value||t.classList.remove(`has-content`)}),e.addEventListener(`input`,()=>{e.value?t.classList.add(`has-content`):t.classList.remove(`has-content`)})})}document.addEventListener(`DOMContentLoaded`,e);